class Solution {
    public int maxFreq(String s, int maxLetters, int minSize, int maxSize) {
        int max = 0;
        Map<String, Integer> map = new HashMap<>();
        for (int i = 0; i <= s.length() - maxSize; i++) {
            for (int j = minSize; j <= maxSize && i + j <= s.length(); j++) {
                String substring = s.substring(i, i + j);
                if (substring.length() == j && new HashSet<>(substring.chars().boxed().collect(Collectors.toList())).size() <= maxLetters) {
                    max = Math.max(max, map.put(substring, map.getOrDefault(substring, 0) + 1));
                }
            }
        }
        return max;
    }
}
